      "2  2026-04-01   Bolton   13920000.0\\n",
      "3  2026-03-27   Bolton   20880000.0\\n",
      "4  2026-03-25   Bolton   22320000.0\\n",
      "5  2026-03-23   Bolton   13200000.0\\n",
      "6  2026-03-19   Bolton   16560000.0\\n",
